import{_ as a,o as t,c as i,a3 as n}from"./chunks/framework.aYYe0dfI.js";const u=JSON.parse('{"title":"clore::extract::ensurecachekey","description":"The function clore::extract::ensure_cache_key serves as a thin entry point that delegates entirely to the implementation function ensure_cache_key_impl. Its purpose is to separate the public interface from the actual cache-key computation logic, allowing the implementation details—such as argument sanitization, compiler invocation parsing, file normalization, and hash generation—to evolve without affecting callers. The single call to ensure_cache_key_impl handles all internal control flow, including conditional checks for cached toolchain data, error handling for missing or invalid compilation databases, and the final assignment of the CompileEntry::cache_key field.","frontmatter":{"title":"clore::extract::ensurecachekey","description":"The function clore::extract::ensure_cache_key serves as a thin entry point that delegates entirely to the implementation function ensure_cache_key_impl. Its purpose is to separate the public interface from the actual cache-key computation logic, allowing the implementation details—such as argument sanitization, compiler invocation parsing, file normalization, and hash generation—to evolve without affecting callers. The single call to ensure_cache_key_impl handles all internal control flow, including conditional checks for cached toolchain data, error handling for missing or invalid compilation databases, and the final assignment of the CompileEntry::cache_key field.","layout":"doc","template":"doc"},"headers":[],"relativePath":"clore/modules/extract/functions/ensure-cache-key.md","filePath":"en/clore/modules/extract/functions/ensure-cache-key.md"}'),l={name:"clore/modules/extract/functions/ensure-cache-key.md"};function c(o,e,s,r,h,d){return t(),i("div",null,[...e[0]||(e[0]=[n("",20)])])}const m=a(l,[["render",c]]);export{u as __pageData,m as default};
